  slug: "best-cities-for-brand-activations",
  heroImage: "https://images.unsplash.com/photo-1518391846015-55a9cc003b25?auto=format&fit=crop&w=1600&q=80",
  title: "The Best Cities in America for Brand Activations",
  dek: "Twenty markets, ranked by the combination of foot traffic, permit friendliness, venue inventory, and the always-underrated 'will the weather cooperate?' factor.",
  category: "Industry",
